item = _input.item.json

summary  = (item.get('summary') or '').lower()
attendees = item.get('attendeeCount', 0)

# Keyword maps per category
DEEP_WORK    = ['focus', 'deep work', 'writing', 'coding', 'research', 'review', 'analysis', 'blocked', 'no meeting', 'heads down', 'design']
COLLABORATION = ['brainstorm', 'planning', 'sprint', 'standup', 'sync', 'team', 'workshop', 'kickoff', 'retrospective', 'demo', 'presentation', 'all hands']
ONE_ON_ONE   = ['1:1', '1-1', 'one on one', 'one-on-one', 'catch up', 'check-in', 'checkin']
ADMIN        = ['interview', 'onboarding', 'hr', 'finance', 'budget', 'admin', 'payroll', 'compliance', 'legal', 'contract']
EXTERNAL     = ['client', 'customer', 'sales', 'demo', 'prospect', 'vendor', 'partner', 'discovery']
PERSONAL     = ['lunch', 'break', 'gym', 'coffee', 'personal', 'family', 'doctor', 'appointment']

def classify(s, n_attendees):
    if any(k in s for k in PERSONAL):
        return 'personal'
    if any(k in s for k in DEEP_WORK):
        return 'deep_work'
    if any(k in s for k in ONE_ON_ONE) or n_attendees == 2:
        return 'one_on_one'
    if any(k in s for k in EXTERNAL):
        return 'external'
    if any(k in s for k in ADMIN):
        return 'admin'
    if any(k in s for k in COLLABORATION) or n_attendees >= 3:
        return 'collaboration'
    return 'uncategorized'

category = classify(summary, attendees)

# Is this a focus block (solo, 30+ min, no attendees)
is_focus_block = (
    attendees == 0 and
    item.get('durationMinutes', 0) >= 30 and
    category in ('deep_work', 'uncategorized')
)

return {
    'json': {
        **item,
        'category':      category,
        'isFocusBlock':  is_focus_block,
        'isMeeting':     attendees >= 2 or category in ('collaboration', 'one_on_one', 'external')
    }
}

