// Merge AI insights with pattern metrics and format final output payload
const aiItem    = $input.all()[0].json;
const metricsRaw = $('Python - Pattern Detection Engine').all()[0].json;

const insightText = aiItem.output || aiItem.response || aiItem.text || 'No insights generated.';

// Compute a simple health score 0-100
const focusRatio   = metricsRaw.totalFocusMinutes / Math.max(metricsRaw.totalScheduledMinutes, 1);
const b2bPenalty   = Math.min(metricsRaw.maxBackToBackChain * 8, 40);
const fragPenalty  = Math.round(metricsRaw.fragmentationScore * 0.3);
const healthScore  = Math.max(0, Math.min(100, Math.round(50 + focusRatio * 50 - b2bPenalty - fragPenalty)));

const formattedDate = new Date().toISOString().split('T')[0];

return [{
  json: {
    reportDate:              formattedDate,
    healthScore:             healthScore,
    totalEvents:             metricsRaw.totalEvents,
    totalMeetingHours:       +(metricsRaw.totalMeetingMinutes / 60).toFixed(1),
    totalFocusHours:         +(metricsRaw.totalFocusMinutes / 60).toFixed(1),
    peakMeetingHour:         metricsRaw.peakMeetingHour,
    heaviestDay:             metricsRaw.heaviestDay,
    maxBackToBackChain:      metricsRaw.maxBackToBackChain,
    fragmentationScore:      metricsRaw.fragmentationScore,
    categoryMinutesJSON:     metricsRaw.categoryMinutesJSON,
    suboptimalFlags:         metricsRaw.suboptimalFlagsJSON,
    freeBlocks:              metricsRaw.freeBlocksJSON,
    aiInsights:              insightText,
    emailSubject:            `📅 Calendar Optimization Report — ${formattedDate} | Health Score: ${healthScore}/100`
  }
}];
